/**
 * Return shortstat numbers (file count, total lines changed) for a worktree against base SHA, including untracked files. Used by Phase 3 scoring without the node_modules-explosion bug of worktreeDiff. Untracked files are counted via direct filesystem read since they're not in the git index.
 */
// @kern-source: git:449
export function worktreeChangedShortstat(cwd: string, baseSha: string): {filesChanged:number,linesChanged:number} {
  let filesChanged = 0;
  let linesChanged = 0;
  try {
    // Tracked changes
    const trackedStat = git(['diff', baseSha, '--shortstat', '--'], cwd);
    // Format: " 3 files changed, 47 insertions(+), 12 deletions(-)"
    const fileMatch = trackedStat.match(/(\d+)\s+files?\s+changed/);
    const insMatch = trackedStat.match(/(\d+)\s+insertions?/);
    const delMatch = trackedStat.match(/(\d+)\s+deletions?/);
    if (fileMatch) filesChanged += parseInt(fileMatch[1], 10);
    if (insMatch) linesChanged += parseInt(insMatch[1], 10);
    if (delMatch) linesChanged += parseInt(delMatch[1], 10);
    // Untracked files (count files + lines).
    // Gemini code review fix #4: skip git show :file — untracked files by
    // definition aren't in the index, so that call always failed. Read the
    // file directly from disk via fs.readFileSync (handles paths with spaces;
    // wc -l doesn't quote properly when invoked via execFile).
    const untracked = git(['ls-files', '--others', '--exclude-standard'], cwd);
    const untrackedFiles = untracked.split('\n').filter((l: string) => l.trim());
    filesChanged += untrackedFiles.length;
    for (const file of untrackedFiles) {
      const fullPath = join(cwd, file);
      try {
        // Read as raw buffer first so we can detect binary by scanning for
        // null bytes — readFileSync(path, 'utf-8') would throw on binary
        // with an inscrutable error, swallowing the type information.
        const buf = readFileSync(fullPath);
        // Binary heuristic: presence of NUL byte in first 8KB. Skip silently.
        let isBinary = false;
        const sample = buf.slice(0, Math.min(buf.length, 8192));
        for (let i = 0; i < sample.length; i++) {
          if (sample[i] === 0) { isBinary = true; break; }
        }
        if (isBinary) continue;
        // Count newlines + 1 for trailing line without newline. Matches wc -l
        // semantics but handles paths with spaces (which wc -l invoked via
        // execFile does NOT) and binary detection (which utf-8 readFileSync
        // does NOT — it would throw on first invalid byte sequence).
        const content = buf.toString('utf-8');
        const newlineCount = (content.match(/\n/g) ?? []).length;
        linesChanged += newlineCount + (content.length > 0 && !content.endsWith('\n') ? 1 : 0);
      } catch (err: unknown) {
        // OpenCode review fix #3: categorize the catch instead of
        // silently swallowing every error type.
        const e = err as { code?: string };
        if (e.code === 'ENOENT') {
          // File deleted between ls-files and read — racy but harmless, skip silently.
        } else if (e.code === 'EACCES' || e.code === 'EPERM') {
          console.warn(`[agon] worktreeChangedShortstat: permission denied reading ${file}`);
        } else {
          console.warn(`[agon] worktreeChangedShortstat: failed to read ${file}: ${err instanceof Error ? err.message : String(err)}`);
        }
      }
    }
  } catch (err) {
    console.warn(`[agon] worktreeChangedShortstat failed: ${err instanceof Error ? err.message : String(err)}`);
  }
  return { filesChanged, linesChanged };
}

